    def solve(self, nums):
        s = set()
        for num in nums:
            s.add(num)
        if len(s) == 1:
            return True
        count = 0
        for num in nums:
            if num in s:
                s.remove(num)
                count += 1
                if count > 0:
                    break
            else:
                s.add(num)
        return count > 0

