class Solution {
  bool solve(vector<int>& nums) {
    set<int> s;
    for (int num : nums) {
      s.insert(num);
    }
    if (s.size() == 1) return true;
    int count = 0;
    for (int num : nums) {
      if (s.find(num) != s.end()) {
        s.erase(num);
        count++;
        if (count > 0) break;
      } else {
        s.insert(num);
      }
    }
    return count > 0;
  }
};

